import { IMessageComposer } from '@nitrots/nitro-renderer';

export class MythicalBlueprintRemoveItemComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(sessionId: number, blueprintItemId: number, slotIndex: number)
{
// Must match MythicalBlueprintRemoveItemEvent.java order EXACTLY:
// sessionId, blueprintItemId, slotIndex
this._data = [
sessionId,
blueprintItemId,
slotIndex
];

console.log('Packet MythicalBlueprintRemoveItemComposer sent');
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}